    pub fn downgrade(arc: &Arc<dyn Fn(T) + Send + Sync>) -> Self {
        Self::from_arc(arc)
    }
}

impl<T: 'static> From<&Arc<dyn Fn(T) + Send + Sync>> for WeakSend<T> {
    fn from(arc: &Arc<dyn Fn(T) + Send + Sync>) -> Self {
        WeakSend(Arc::downgrade(arc))
    }
}

