    const fn state_token(&self) -> &'static str {
        match self.state {
            State::Idle => "idle",
            State::Copying => "copying",
            State::Copied => "copied",
            State::Error => "error",
        }
    }

    fn trigger_label(&self) -> String {
        match self.state {
