            State::Copying => (self.ctx.messages.copying_label)(&self.ctx.locale),
            State::Copied => (self.ctx.messages.copied_label)(&self.ctx.locale),
            State::Error => (self.ctx.messages.error_label)(&self.ctx.locale),
